# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

import redis
from rediscluster import RedisCluster

# Define the list of startup nodes for the Redis cluster
startup_nodes = [
    {"host": "redis-node-1", "port": "6379"},
    {"host": "redis-node-2", "port": "6379"},
    {"host": "redis-node-3", "port": "6379"}
]

# Initialize the RedisCluster connection
rc = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

def store_user_data(user_id, session_token, api_key):
    # Define TTL values for session token and API key (e.g., 1 hour)
    ttl_session_token = 3600
    ttl_api_key = 86400

    # Store session token in Redis with TTL
    rc.set(f"session:{user_id}", session_token, ex=ttl_session_token)

    # Store API key in Redis with TTL
    rc.set(f"api_key:{user_id}", api_key, ex=ttl_api_key)

def get_user_data(user_id):
    # Retrieve session token from Redis
    session_token = rc.get(f"session:{user_id}")

    # Retrieve API key from Redis
    api_key = rc.get(f"api_key:{user_id}")

    return session_token, api_key

# Example usage
if __name__ == "__main__":
    user_id = "user123"
    session_token = "example_session_token_123"
    api_key = "example_api_key_456"

    # Store user data
    store_user_data(user_id, session_token, api_key)

    # Retrieve and print user data
    retrieved_session_token, retrieved_api_key = get_user_data(user_id)
    print(f"Session Token: {retrieved_session_token}")
    print(f"API Key: {retrieved_api_key}")